package com.seaquake6324.civitas.infrastructure.border;
import java.util.Optional;import java.util.UUID;import net.minecraft.nbt.CompoundTag;import net.minecraft.world.entity.Mob;
public final class InvasionMobMarker{private static final String KEY="civitas:invasion";public static void mark(Mob mob,UUID invasion){CompoundTag tag=new CompoundTag();tag.putString("Id",invasion.toString());tag.putBoolean("Active",true);mob.getPersistentData().put(KEY,tag);InvasionMobIndex.register(mob);}public static boolean active(Mob mob){return mob.getPersistentData().getCompound(KEY).map(t->t.getBooleanOr("Active",false)).orElse(false);}public static Optional<UUID>invasionId(Mob mob){return mob.getPersistentData().getCompound(KEY).flatMap(t->{try{String value=t.getStringOr("Id","");return value.isBlank()?Optional.empty():Optional.of(UUID.fromString(value));}catch(IllegalArgumentException exception){return Optional.empty();}});}public static boolean belongs(Mob mob,UUID id){return invasionId(mob).filter(id::equals).isPresent();}public static void release(Mob mob){mob.getPersistentData().getCompound(KEY).ifPresent(t->t.putBoolean("Active",false));}private InvasionMobMarker(){}}
